mapper.update:
UPDATE LABOR_CONTRACTS
SET STATUS          = 'SENT',
    OWNER_SIGNED_AT = #{ownerSignedAt},
    SENT_AT         = #{sentAt}
WHERE ID = #{id}
  AND STATUS = 'DRAFT'

UPDATE LABOR_CONTRACTS
SET STATUS             = 'SIGNED',
    EMPLOYEE_SIGNED_AT = #{employeeSignedAt}
WHERE ID = #{id}
  AND STATUS = 'SENT'

UPDATE LABOR_CONTRACTS
SET STATUS          = 'REJECTED',
    REJECTED_REASON = #{rejectedReason}
WHERE ID = #{id}
  AND STATUS = 'SENT'
